function Form() {
  function cadastrarUsuario() {
    alert("Usuário cadastrado com sucesso!");
  }
  return (
    <div>
      <h1>Formulário de Contato</h1>
      <form onSubmit={cadastrarUsuario}>
        <div>
          <input type="text" placeholder="Digite seu nome" />
        </div>
        <div>
          <input type="submit" value="Enviar" />
        </div>
      </form>
    </div>
  );
}
export default Form;
